*/

package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"
)

// mockTransformer is a test helper that implements the Transformer interface
// for testing purposes. It can simulate various transformation behaviors.
type mockTransformer struct {
	encryptResult []byte
	decryptResult []byte
	encryptErr    error
	decryptErr    error
	stale         bool
	calls         map[string]int
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if m.calls == nil {
		m.calls = make(map[string]int)
	}
	m.calls["TransformToStorage"]++
	if m.encryptErr != nil {
		return nil, m.encryptErr
	}
	return m.encryptResult, nil
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if m.calls == nil {
		m.calls = make(map[string]int)
	}
	m.calls["TransformFromStorage"]++
	if m.decryptErr != nil {
		return nil, false, m.decryptErr
	}
	return m.decryptResult, m.stale, nil
}

// TestTransformerInterfaceContract verifies that transformers implement the basic
// contract of being able to round-trip data through TransformToStorage and TransformFromStorage.
func TestTransformerInterfaceContract(t *testing.T) {
	tests := []struct {
		name        string
		transformer Transformer
		original    []byte
		encrypted   []byte
		expectErr   bool
	}{
		{
			name: "successful round-trip",
			transformer: &mockTransformer{
				encryptResult: []byte("encrypted"),
				decryptResult: []byte("original"),
			},
			original:  []byte("original"),
			encrypted: []byte("encrypted"),
			expectErr: false,
		},
		{
			name: "encryption error",
			transformer: &mockTransformer{
				encryptErr: fmt.Errorf("encryption failed"),
			},
			original:  []byte("original"),
			expectErr: true,
		},
		{
			name: "decryption error",
			transformer: &mockTransformer{
				encryptResult: []byte("encrypted"),
				decryptErr:    fmt.Errorf("decryption failed"),
			},
			original:  []byte("original"),
			encrypted: []byte("encrypted"),
			expectErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := context.Background()

			// Transform to storage
			encrypted, err := tt.transformer.TransformToStorage(ctx, tt.original, nil)
			if (err != nil) != tt.expectErr {
				t.Fatalf("TransformToStorage: unexpected error: %v", err)
			}
			if err != nil {
				return
			}
			if !bytes.Equal(encrypted, tt.encrypted) {
				t.Errorf("TransformToStorage: got %q, want %q", encrypted, tt.encrypted)
			}

			// Transform from storage
			decrypted, stale, err := tt.transformer.TransformFromStorage(ctx, tt.encrypted, nil)
			if (err != nil) != tt.expectErr {
				t.Fatalf("TransformFromStorage: unexpected error: %v", err)
			}
			if err != nil {
				return
			}
			if !bytes.Equal(decrypted, tt.original) {
				t.Errorf("TransformFromStorage: got %q, want %q", decrypted, tt.original)
			}
			if stale {
				t.Errorf("TransformFromStorage: unexpected stale flag")
			}
		})
	}
}

// TestEmptyValueTransformation tests the handling of empty byte slices
// in both encryption and decryption.
func TestEmptyValueTransformation(t *testing.T) {
	tests := []struct {
		name      string
		input     []byte
		direction string
	}{
		{
			name:      "empty to_storage",
			input:     []byte{},
			direction: "to_storage",
		},
		{
			name:      "empty from_storage",
			input:     []byte{},
			direction: "from_storage",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformer := &mockTransformer{
				encryptResult: []byte{},
				decryptResult: []byte{},
			}
			ctx := context.Background()

			if tt.direction == "to_storage" {
				result, err := transformer.TransformToStorage(ctx, tt.input, nil)
				if err != nil {
					t.Fatalf("TransformToStorage failed: %v", err)
				}
				if len(result) != 0 {
					t.Errorf("expected empty result, got %q", result)
				}
			} else {
				result, _, err := transformer.TransformFromStorage(ctx, tt.input, nil)
				if err != nil {
					t.Fatalf("TransformFromStorage failed: %v", err)
				}
				if len(result) != 0 {
					t.Errorf("expected empty result, got %q", result)
				}
			}
		})
	}
}

// TestDefaultContext tests the DefaultContext implementation of the Context interface.
func TestDefaultContext(t *testing.T) {
	tests := []struct {
		name         string
		data         []byte
		expected     []byte
		expectPanic  bool
	}{
		{
			name:        "valid context data",
			data:        []byte("test-data"),
			expected:    []byte("test-data"),
			expectPanic: false,
		},
		{
			name:        "empty context data",
			data:        []byte{},
			expected:    []byte{},
			expectPanic: false,
		},
		{
			name:        "nil context data",
			data:        nil,
			expected:    nil,
			expectPanic: false,
		},
		{
			name:        "binary context data",
			data:        []byte{0x00, 0x01, 0x02, 0xff},
			expected:    []byte{0x00, 0x01, 0x02, 0xff},
			expectPanic: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx := DefaultContext(tt.data)
			result := ctx.AuthenticatedData()
			if !bytes.Equal(result, tt.expected) {
				t.Errorf("AuthenticatedData: got %v, want %v", result, tt.expected)
			}
		})
	}
}

// TestPrefixTransformerMatchingBehavior tests that PrefixTransformer correctly
// identifies and uses transformers based on their prefixes.
func TestPrefixTransformerMatchingBehavior(t *testing.T) {
	tests := []struct {
		name         string
		data         []byte
		transformers []PrefixTransformer
		expectMatch  bool
		expectIdx    int
	}{
		{
			name: "first prefix matches",
			data: []byte("prefix1:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("prefix1:"), Transformer: &mockTransformer{}},
				{Prefix: []byte("prefix2:"), Transformer: &mockTransformer{}},
			},
			expectMatch: true,
			expectIdx:   0,
		},
		{
			name: "second prefix matches",
			data: []byte("prefix2:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("prefix1:"), Transformer: &mockTransformer{}},
				{Prefix: []byte("prefix2:"), Transformer: &mockTransformer{}},
			},
			expectMatch: true,
			expectIdx:   1,
		},
		{
			name: "no prefix matches",
			data: []byte("prefix3:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("prefix1:"), Transformer: &mockTransformer{}},
				{Prefix: []byte("prefix2:"), Transformer: &mockTransformer{}},
			},
			expectMatch: false,
		},
		{
			name: "empty prefix matches any data",
			data: []byte("any data here"),
			transformers: []PrefixTransformer{
				{Prefix: []byte{}, Transformer: &mockTransformer{
					decryptResult: []byte("any data here"),
				}},
			},
			expectMatch: true,
			expectIdx:   0,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			pt := NewPrefixTransformers(fmt.Errorf("no matching transformer"), tt.transformers...)
			_, _, err := pt.TransformFromStorage(context.Background(), tt.data, nil)

			if tt.expectMatch && err != nil {
				t.Errorf("expected match but got error: %v", err)
			}
			if !tt.expectMatch && err == nil {
				t.Errorf("expected no match but succeeded")
			}
		})
	}
}

// TestPrefixTransformerStaleMarking tests that PrefixTransformer correctly marks
// data as stale when it's not encrypted with the primary transformer.
func TestPrefixTransformerStaleMarking(t *testing.T) {
	tests := []struct {
		name           string
		data           []byte
		primaryIdx     int
		expectStale    bool
		transformError error
	}{
		{
			name: "primary transformer returns non-stale",
			data: []byte("primary:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("primary:"), Transformer: &mockTransformer{
					decryptResult: []byte("data"),
					stale:         false,
				}},
				{Prefix: []byte("secondary:"), Transformer: &mockTransformer{}},
			},
			primaryIdx:  0,
			expectStale: false,
		},
		{
			name: "secondary transformer always marked stale",
			data: []byte("secondary:data"),
			transformers: []PrefixTransformer{
				{Prefix: []byte("primary:"), Transformer: &mockTransformer{}},
				{Prefix: []byte("secondary:"), Transformer: &mockTransformer{
					decryptResult: []byte("data"),
					stale:         false,
				}},
			},
			primaryIdx:  0,
			expectStale: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			pt := NewPrefixTransformers(fmt.Errorf("no match"), tt.transformers...)
			_, stale, err := pt.TransformFromStorage(context.Background(), tt.data, nil)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}
			if stale != tt.expectStale {
				t.Errorf("stale: got %v, want %v", stale, tt.expectStale)
			}
		})
	}
}

// TestPrefixTransformerMismatch tests the error handling when data doesn't match
// any registered prefix transformer.
func TestPrefixTransformerMismatch(t *testing.T) {
	customErr := fmt.Errorf("custom mismatch error")
	pt := NewPrefixTransformers(customErr,
		PrefixTransformer{Prefix: []byte("known:"), Transformer: &mockTransformer{}},
	)

	_, _, err := pt.TransformFromStorage(context.Background(), []byte("unknown:data"), nil)
	if err != customErr {
		t.Errorf("expected custom error, got: %v", err)
	}
}

// TestPrefixTransformerErrorPropagation tests that errors from the underlying
// transformer are properly propagated to the caller.
func TestPrefixTransformerErrorPropagation(t *testing.T) {
	tests := []struct {
		name      string
		setupErr  error
		operation string
	}{
		{
			name:      "encryption error propagated",
			setupErr:  fmt.Errorf("encryption failed"),
			operation: "to_storage",
		},
		{
			name:      "decryption error propagated",
			setupErr:  fmt.Errorf("decryption failed"),
			operation: "from_storage",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			mock := &mockTransformer{
				encryptErr: tt.setupErr,
				decryptErr: tt.setupErr,
			}
			pt := NewPrefixTransformers(
				fmt.Errorf("no match"),
				PrefixTransformer{Prefix: []byte("test:"), Transformer: mock},
			)

			if tt.operation == "to_storage" {
				_, err := pt.TransformToStorage(context.Background(), []byte("data"), nil)
				if err != tt.setupErr {
					t.Errorf("expected %v, got %v", tt.setupErr, err)
				}
			} else {
				_, _, err := pt.TransformFromStorage(context.Background(), []byte("test:data"), nil)
				if err != tt.setupErr {
					t.Errorf("expected %v, got %v", tt.setupErr, err)
				}
			}
		})
	}
}

// TestPrefixTransformerToStorageUsesFirst tests that TransformToStorage always
// uses the first transformer in the list, regardless of what's in the data.
func TestPrefixTransformerToStorageUsesFirst(t *testing.T) {
	firstTransformer := &mockTransformer{
		encryptResult: []byte("encrypted-with-first"),
	}
	secondTransformer := &mockTransformer{
		encryptResult: []byte("encrypted-with-second"),
	}

	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: firstTransformer},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: secondTransformer},
	)

	result, err := pt.TransformToStorage(context.Background(), []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	// Result should have the first prefix and use first transformer's output
	expected := append([]byte("first:"), []byte("encrypted-with-first")...)
	if !bytes.Equal(result, expected) {
		t.Errorf("expected %q, got %q", expected, result)
	}

	// Verify second transformer was not called
	if secondTransformer.calls["TransformToStorage"] > 0 {
		t.Error("second transformer should not be called")
	}
}

// TestPrefixTransformerPrefixStripping tests that prefixes are correctly stripped
// before passing data to the underlying transformer and re-added on output.
func TestPrefixTransformerPrefixStripping(t *testing.T) {
	mock := &mockTransformer{
		encryptResult: []byte("output"),
		decryptResult: []byte("output"),
	}
	prefix := []byte("prefix:separator:")

	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: prefix, Transformer: mock},
	)

	// Test with TransformToStorage
	result, err := pt.TransformToStorage(context.Background(), []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	// Verify prefix was added
	if !bytes.HasPrefix(result, prefix) {
		t.Errorf("result should have prefix, got %q", result)
	}

	// Test with TransformFromStorage
	mock.decryptResult = []byte("decrypted-data")
	inputWithPrefix := append(append([]byte{}, prefix...), []byte("encrypted-value")...)
	result, _, err := pt.TransformFromStorage(context.Background(), inputWithPrefix, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	// Verify result is correct (prefix should have been stripped before transformer)
	if !bytes.Equal(result, []byte("decrypted-data")) {
		t.Errorf("expected decrypted data, got %q", result)
	}
}

// TestTransformerContextPassing tests that the Context parameter is correctly
// passed through the transformer interface.
func TestTransformerContextPassing(t *testing.T) {
	dataCtx := DefaultContext([]byte("authenticated-data"))
	mock := &mockTransformer{
		encryptResult: []byte("encrypted"),
		decryptResult: []byte("decrypted"),
	}

	// TransformToStorage with context
	_, err := mock.TransformToStorage(context.Background(), []byte("data"), dataCtx)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	// TransformFromStorage with context
	_, _, err = mock.TransformFromStorage(context.Background(), []byte("data"), dataCtx)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	// Verify context was used (implicitly through the call)
	if dataCtx.AuthenticatedData() == nil {
		t.Error("context should contain authenticated data")
	}
}

// TestMultipleTransformersFallback tests the behavior when multiple transformers
// with the same or similar prefixes are registered, and earlier ones fail.
func TestMultipleTransformersFallback(t *testing.T) {
	tests := []struct {
		name           string
		transformers   []PrefixTransformer
		data           []byte
		shouldSucceed  bool
		shouldMatchIdx int
	}{
		{
			name: "first transformer fails, second succeeds",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("enc:"),
					Transformer: &mockTransformer{
						decryptErr: fmt.Errorf("wrong key"),
					},
				},
				{
					Prefix: []byte("enc:"),
					Transformer: &mockTransformer{
						decryptResult: []byte("success"),
					},
				},
			},
			data:           []byte("enc:encrypteddata"),
			shouldSucceed:  true,
			shouldMatchIdx: 1,
		},
		{
			name: "all transformers fail",
			transformers: []PrefixTransformer{
				{
					Prefix: []byte("enc:"),
					Transformer: &mockTransformer{
						decryptErr: fmt.Errorf("wrong key 1"),
					},
				},
				{
					Prefix: []byte("enc:"),
					Transformer: &mockTransformer{
						decryptErr: fmt.Errorf("wrong key 2"),
					},
				},
			},
			data:          []byte("enc:encrypteddata"),
			shouldSucceed: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			pt := NewPrefixTransformers(fmt.Errorf("no match"), tt.transformers...)
			_, _, err := pt.TransformFromStorage(context.Background(), tt.data, nil)

			if tt.shouldSucceed && err != nil {
				t.Errorf("expected success but got error: %v", err)
			}
			if !tt.shouldSucceed && err == nil {
				t.Errorf("expected error but succeeded")
			}
		})
	}
}

// TestLargeDataTransformation tests transformer behavior with large data payloads.
func TestLargeDataTransformation(t *testing.T) {
	largeData := make([]byte, 1024*1024) // 1MB of data
	for i := range largeData {
		largeData[i] = byte(i % 256)
	}

	mock := &mockTransformer{
		encryptResult: largeData,
		decryptResult: largeData,
	}

	pt := NewPrefixTransformers(
		fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("large:"), Transformer: mock},
	)

	// Test encryption of large data
	result, err := pt.TransformToStorage(context.Background(), largeData, nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}
	if len(result) != len(largeData)+6 { // 6 bytes for "large:" prefix
		t.Errorf("result size mismatch: got %d, want %d", len(result), len(largeData)+6)
	}

	// Test decryption of large data
	dataWithPrefix := append([]byte("large:"), largeData...)
	decrypted, _, err := pt.TransformFromStorage(context.Background(), dataWithPrefix, nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}
	if !bytes.Equal(decrypted, largeData) {
		t.Error("decrypted data doesn't match original")
	}
}

// TestPrefixTransformerWithIdentityPrefix tests special handling of empty prefix
// (identity transformer), particularly the error-skipping behavior.
func TestPrefixTransformerWithIdentityPrefix(t *testing.T) {
	tests := []struct {
		name              string
		identityErr       error
		secondaryData     []byte
		expectSecondaryErr bool
	}{
		{
			name:        "identity fails, secondary succeeds",
			identityErr: fmt.Errorf("identity verification failed"),
			secondaryData: []byte("secondary:data"),
		},
		{
			name:           "identity succeeds",
			identityErr:    nil,
			secondaryData:  []byte("plaintext"),
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			transformers := []PrefixTransformer{
				{
					Prefix: []byte{}, // Identity transformer
					Transformer: &mockTransformer{
						decryptErr: tt.identityErr,
					},
				},
				{
					Prefix: []byte("secondary:"),
					Transformer: &mockTransformer{
						decryptResult: []byte("success"),
					},
				},
			}

			pt := NewPrefixTransformers(fmt.Errorf("no match"), transformers...)

			if tt.identityErr != nil {
				// When identity fails, it should try secondary
				_, _, err := pt.TransformFromStorage(context.Background(), tt.secondaryData, nil)
				// Should succeed because secondary matches
				if err != nil {
					t.Errorf("expected success with secondary fallback, got: %v", err)
				}
			} else {
				// When identity succeeds, it should use that
				_, _, err := pt.TransformFromStorage(context.Background(), tt.secondaryData, nil)
				// Should succeed with identity
				if err != nil {
					t.Errorf("unexpected error: %v", err)
				}
			}
		})
	}
}

// TestContextInterface tests various implementations of the Context interface.
func TestContextInterface(t *testing.T) {
	tests := []struct {
		name     string
		ctx      Context
		expected []byte
	}{
		{
			name:     "DefaultContext with data",
			ctx:      DefaultContext([]byte("test")),
			expected: []byte("test"),
		},
		{
			name:     "DefaultContext empty",
			ctx:      DefaultContext([]byte{}),
			expected: []byte{},
		},
		{
			name:     "DefaultContext nil",
			ctx:      DefaultContext(nil),
			expected: nil,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := tt.ctx.AuthenticatedData()
			if !bytes.Equal(result, tt.expected) {
				t.Errorf("expected %v, got %v", tt.expected, result)
			}
		})
	}
}

